// Pull both ensures-foralls into the proof context with explicit
// triggers, so z3 instantiates them on the same `i` in both runs.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: for each i in range, post1 and post2 yield the same Page.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At the modified index every Page field is fixed by ensures:
        // addr, state, is_io_page, rev_pointer, owning_container,
        // mappings, io_mappings all =~= pre_self_.page_array@[index].*
        // on both runs, and ref_count =~= ref_count on both runs.
        // Struct extensionality (=~=) lifts these field equalities.
    } else {
        // Outside the modified index both foralls fire and force
        // post1.page_array@[i] =~= pre.page_array@[i] =~= post2.page_array@[i].
    }
}

// Sequence extensionality lifts the pointwise equality to Seq<Page>.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
